# Category: hardcoded_secrets

import boto3
import sys

# Option 1: Pass credentials at runtime (safest for a quick demo)
# Run as: python list_s3.py <access_key> <secret_key>

# Option 2: The script will prompt interactively if no arguments are given

BUCKET_NAME = "demo-bucket"


def get_credentials():
    if len(sys.argv) == 3:
        return sys.argv[1], sys.argv[2]
    else:
        print("Enter AWS credentials (these will not be stored):")
        access_key = input("  AWS Access Key ID: ").strip()
        secret_key = input("  AWS Secret Access Key: ").strip()
        return access_key, secret_key


def list_bucket_files(bucket_name, access_key, secret_key):
    session = boto3.Session(
        aws_access_key_id=access_key,
        aws_secret_access_key=secret_key,
    )
    s3_client = session.client("s3")

    print(f"\nFiles in bucket '{bucket_name}':")
    print("-" * 60)

    paginator = s3_client.get_paginator("list_objects_v2")
    file_count = 0

    for page in paginator.paginate(Bucket=bucket_name):
        if "Contents" in page:
            for obj in page["Contents"]:
                size_kb = obj["Size"] / 1024
                print(f"  {obj['Key']:<45} {size_kb:>8.1f} KB   {obj['LastModified']}")
                file_count += 1

    print("-" * 60)
    print(f"Total files: {file_count}")


if __name__ == "__main__":
    try:
        access_key, secret_key = get_credentials()
        list_bucket_files(BUCKET_NAME, access_key, secret_key)
    except Exception as e:
        print(f"Error: {e}")
        sys.exit(1)